class Solution:
    def maximumRobots(self, chargeTimes, runningCosts, budget):
        n = len(chargeTimes)
        best = 0
        for i in range(n):
            mx = 0
            s = 0
            for j in range(i, n):
                mx = max(mx, chargeTimes[j])
                s += runningCosts[j]
                k = j - i + 1
                if mx + k * s <= budget:
                    best = max(best, k)
                else:
                    break
        return best

