class Solution:
    def maximumRobots(self, chargeTimes, runningCosts, budget):
        from collections import deque
        n = len(chargeTimes)
        dq = deque()
        s = 0
        left = 0
        best = 0
        for right in range(n):
            while dq and chargeTimes[dq[-1]] <= chargeTimes[right]:
                dq.pop()
            dq.append(right)
            s += runningCosts[right]
            while dq and chargeTimes[dq[0]] + (right - left + 1) * s > budget:
                if dq[0] == left:
                    dq.popleft()
                s -= runningCosts[left]
                left += 1
            best = max(best, right - left + 1)
        return best

