var maximumRobots = function(chargeTimes, runningCosts, budget) {
    const n = chargeTimes.length;
    const bud = BigInt(budget);
    const dq = [];
    let s = 0n;
    let left = 0;
    let best = 0;
    for (let right = 0; right < n; right++) {
        while (dq.length && chargeTimes[dq[dq.length - 1]] <= chargeTimes[right]) dq.pop();
        dq.push(right);
        s += BigInt(runningCosts[right]);
        while (dq.length && BigInt(chargeTimes[dq[0]]) + BigInt(right - left + 1) * s > bud) {
            if (dq[0] === left) dq.shift();
            s -= BigInt(runningCosts[left]);
            left++;
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
};
